import{p as r,bx as o,bh as e,I as h,U as i,A as t,W as a,X as s}from"./chunks/framework.BpabEsSf.js";const y=JSON.parse('{"title":"Local Storage & Encryption Tech Doc","description":"","frontmatter":{"title":"Local Storage & Encryption Tech Doc","date":"2026-05-16T13:15:00.000Z","permalink":"/reference/android-storage-security","categories":["Technical Insights"],"tags":["Android","Security","Encryption"]},"headers":[],"relativePath":"vi/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md","filePath":"vi/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md","lastUpdated":null}'),l={name:"vi/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md"};function u(p,n,d,g,m,b){const c=o("Badge");return e(),h("div",null,[n[7]||(n[7]=i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /vi\\02.Configuration\\02.Docs\\02.Monica Android Local Storage &amp; Encryption Tech Doc.md for this page in Markdown format</div><h1 id="🔒-tai-lieu-ky-thuat-ma-hoa-luu-tru-cuc-bo-monica-android" tabindex="-1">🔒 Tài liệu kỹ thuật mã hóa &amp; lưu trữ cục bộ Monica Android <a class="header-anchor" href="#🔒-tai-lieu-ky-thuat-ma-hoa-luu-tru-cuc-bo-monica-android" aria-label="Permalink to &quot;🔒 Tài liệu kỹ thuật mã hóa &amp; lưu trữ cục bộ Monica Android&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">Kiến trúc Zero-Knowledge</p><p><code>Monica Android</code> triển khai kiến trúc mã hóa xếp chồng nhiều lớp, toàn bộ đĩa và cấp độ trường (field-level) để đảm bảo an ninh tuyệt đối cho các tài sản nhạy cảm của người dùng (như mật khẩu, số thẻ tín dụng, khóa 2FA, ghi chú bảo mật, v.v.) trong quá trình lưu trữ cục bộ và sao lưu WebDAV. Lõi hệ thống tuân thủ nghiêm ngặt khung kiến trúc <strong>Zero-Knowledge (Không tri thức)</strong>: ngay cả khi thiết bị bị mất hoặc các tệp cơ sở dữ liệu bị trích xuất, kẻ tấn công cũng không thể dịch ngược bất kỳ dữ liệu văn bản thuần túy nào nếu không có Mật khẩu chủ của người dùng.</p></div><hr><h2 id="_1-luu-tru-du-lieu-cuc-bo" tabindex="-1">1. Lưu trữ dữ liệu cục bộ <a class="header-anchor" href="#_1-luu-tru-du-lieu-cuc-bo" aria-label="Permalink to &quot;1. Lưu trữ dữ liệu cục bộ&quot;">​</a></h2><p>Monica từ chối lưu trữ SQLite văn bản thuần túy hoặc các cấu hình key-value không đáng tin cậy, hoàn toàn áp dụng các thực hành kiến trúc <strong>Modern Android Development (MAD)</strong> do Google khuyến nghị để quản lý dữ liệu có cấu trúc:</p>',6)),t("ul",null,[n[5]||(n[5]=t("li",null,[t("strong",null,"Tầng lưu trữ cốt lõi"),a(": Được triển khai thông qua "),t("code",null,"Room Persistence Library"),a(" (một tầng trừu tượng tiên tiến phía trên SQLite) để duy trì các Đối tượng truy cập dữ liệu (DAO) có tính gắn kết cao.")],-1)),n[6]||(n[6]=t("li",null,[t("strong",null,"Cơ sở hạ tầng tệp vật lý"),a(": Dữ liệu được ghi trực tiếp vào tệp "),t("code",null,"password_database.db"),a(" nằm trong sandbox và các tệp WAL (Write-Ahead Logging) liên quan của nó.")],-1)),t("li",null,[n[0]||(n[0]=t("strong",null,"Ranh giới cô lập vật lý",-1)),n[1]||(n[1]=a()),s(c,{text:"Cô lập Sandbox",type:"text"}),n[2]||(n[2]=a(": Tất cả các tệp cơ sở dữ liệu nằm trong phân vùng lưu trữ nội bộ riêng tư của ứng dụng (",-1)),n[3]||(n[3]=t("code",null,"/data/data/com.monica.vault/databases/",-1)),n[4]||(n[4]=a("). Hệ điều hành Android thực thi nghiêm ngặt các ranh giới UID cấp hạt nhân để ngăn chặn bất kỳ ứng dụng nào khác trên cùng thiết bị truy cập trái phép vào phân vùng này.",-1))])]),n[8]||(n[8]=i(`<hr><h2 id="_2-chien-luoc-ma-hoa-cap-truong-field-level" tabindex="-1">2. Chiến lược mã hóa cấp trường (Field-Level) <a class="header-anchor" href="#_2-chien-luoc-ma-hoa-cap-truong-field-level" aria-label="Permalink to &quot;2. Chiến lược mã hóa cấp trường (Field-Level)&quot;">​</a></h2><p>Để ngăn chặn các cuộc tấn công rò rỉ bộ nhớ động và bảo vệ dữ liệu chống lại việc trích xuất đĩa ngoại tuyến (offline disk extraction) trong môi trường thiết bị đã root, Monica áp dụng cơ chế mã hóa cấp trường trong tầng Room DAO:</p><h3 id="luong-xu-ly-du-lieu" tabindex="-1">Luồng xử lý dữ liệu: <a class="header-anchor" href="#luong-xu-ly-du-lieu" aria-label="Permalink to &quot;Luồng xử lý dữ liệu:&quot;">​</a></h3><p>Trước khi bất kỳ thực thể dữ liệu nhạy cảm nào được ghi vào đĩa, các trường văn bản thuần túy sẽ đi qua một bộ chuyển đổi loại (Type Converter) tùy chỉnh:</p><p>$$\\text{Plaintext String} \\longrightarrow \\text{AES-256-GCM Encryption} \\longrightarrow \\text{Base64 String} \\longrightarrow \\text{SQLite Storage}$$</p><p>Ngược lại, khi truy vấn dữ liệu, quy trình sẽ được đảo ngược. Các trường không nhạy cảm (như dấu thời gian cập nhật hoặc trạng thái danh mục) vẫn có thể lập chỉ mục để đảm bảo hiệu suất truy vấn cao.</p><hr><h2 id="_3-kien-truc-quan-ly-khoa-phan-cung" tabindex="-1">3. Kiến trúc quản lý khóa phần cứng <a class="header-anchor" href="#_3-kien-truc-quan-ly-khoa-phan-cung" aria-label="Permalink to &quot;3. Kiến trúc quản lý khóa phần cứng&quot;">​</a></h2><p>Khóa mật mã tối cao được sử dụng để mã hóa và giải mã trường cơ sở dữ liệu không bao giờ được lưu trữ tĩnh trên đĩa dưới dạng văn bản thuần túy. Hệ thống quản lý khóa tận dụng tối đa kiến trúc bảo mật phần cứng của Android:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  Mật khẩu chủ của người dùng (Master Password)</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                                     ▼</span></span>
<span class="line"><span>                      [PBKDF2 + HMAC-SHA256] </span></span>
<span class="line"><span>                        (100.000 lần lặp)</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                                     ▼</span></span>
<span class="line"><span>                       Khóa mã hóa khóa (KEK)</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                                     ▼</span></span>
<span class="line"><span>     [Phần cứng cô lập quân sự: Android KeyStore (TEE/SE)]</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                                     ▼</span></span>
<span class="line"><span>                Giải mã Khóa mã hóa dữ liệu gốc (DEK)</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                                     ▼</span></span>
<span class="line"><span>               Mã hóa/Giải mã trường cơ sở dữ liệu cục bộ</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><h3 id="cac-thanh-phan-cot-loi" tabindex="-1">Các thành phần cốt lõi: <a class="header-anchor" href="#cac-thanh-phan-cot-loi" aria-label="Permalink to &quot;Các thành phần cốt lõi:&quot;">​</a></h3><ol><li><strong>Android KeyStore</strong>: Hệ thống tạo và lưu trữ một Khóa mã hóa khóa gốc (Master KEK) bên trong Môi trường thực thi tin cậy (TEE) hoặc Thành phần bảo mật phần cứng (Secure Element - SE). Khóa này không bao giờ có thể bị trích xuất bởi phần mềm.</li><li><strong>Xác thực sinh trắc học</strong>: Việc truy cập vào KeyStore được liên kết trực tiếp với thực thi <code>BiometricPrompt</code> của hệ thống. Chỉ khi xác thực vân tay thành công, phần cứng mới mở khóa tài nguyên mật mã cho phiên làm việc hiện tại.</li></ol><hr><h2 id="_4-quan-ly-cau-hinh-ma-hoa" tabindex="-1">4. Quản lý cấu hình mã hóa <a class="header-anchor" href="#_4-quan-ly-cau-hinh-ma-hoa" aria-label="Permalink to &quot;4. Quản lý cấu hình mã hóa&quot;">​</a></h2><p>Các cấu hình phi cấu trúc của ứng dụng (như trạng thái đăng nhập, tùy chọn giao diện và cờ đồng bộ hóa) được quản lý thông qua thành phần bảo mật Jetpack <strong><code>EncryptedSharedPreferences</code></strong>.</p><p>Thành phần này tự động băm các khóa lưu trữ (key) bằng thuật toán AES-SIV-CMAC và mã hóa các giá trị lưu trữ (value) bằng thuật toán AES-256-GCM, loại bỏ hoàn toàn rủi ro rò rỉ thông tin từ các tệp XML cấu hình truyền thống.</p><hr><h2 id="_5-tom-tat-ma-tran-bao-mat-mat-ma" tabindex="-1">5. Tóm tắt ma trận bảo mật mật mã <a class="header-anchor" href="#_5-tom-tat-ma-tran-bao-mat-mat-ma" aria-label="Permalink to &quot;5. Tóm tắt ma trận bảo mật mật mã&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tầng bảo mật</th><th>Triển khai kỹ thuật</th><th>Vectơ mối đe dọa mục tiêu</th></tr></thead><tbody><tr><td><strong>Lưu trữ dữ liệu cục bộ</strong></td><td><code>AES-256-GCM (256-bit)</code></td><td>Các cuộc tấn công trích xuất cơ sở dữ liệu, giả mạo lật bit vật lý, tiêm kênh kề</td></tr><tr><td><strong>Bảo vệ mật khẩu chủ</strong></td><td><code>PBKDF2 + HMAC-SHA256</code> (100.000 lần lặp)</td><td>Tấn công bẻ khóa ngoại tuyến (brute-force), khớp bảng cầu vồng, quét từ điển</td></tr><tr><td><strong>Bảo vệ khóa Runtime</strong></td><td><code>Android KeyStore (Ranh giới TEE/SE)</code></td><td>Dump bộ nhớ runtime, thoát ranh giới tệp đặc quyền Root, trích xuất chip vật lý</td></tr><tr><td><strong>Đường ống dữ liệu đám mây</strong></td><td>Mã hóa luồng nhị phân cứng <code>MONICA_ENC_V1</code></td><td>Nghe lén trung gian (MITM), rò rỉ nhà cung cấp lưu trữ đám mây, phân tích kích thước dấu chân dữ liệu</td></tr></tbody></table>`,20))])}const v=r(l,[["render",u]]);export{y as __pageData,v as default};
